Version: Deno 2.4.5

```c

static void cleanup(void * argv) {
    (void) argv;
    printf("Cleanup\n");
}


napi_value init(napi_env env, napi_value exports) {
    (void) exports;
    napi_value value;

    // Set the instance data
    void * data = (void *) 1;
    napi_status status = napi_set_instance_data(env, data, cleanup, data);
    assert(status == napi_ok);

    status = napi_create_object(env, &value);
    assert(status == napi_ok);
    return value;
}
NAPI_MODULE(example_addon, init);
```

The callback `cleanup` is not called when runtime exits

